class Solution:
    def heapify(self, nums: list[int]) -> list[int]:
        n = len(nums)
        for i in range(n // 2 - 1, -1, -1):
            self.heapify_helper(nums, i, n)
        return nums

    def heapify_helper(self, nums, i, n):
        largest = i
        left = 2 * i + 1
        right = 2 * i + 2

        if left < n and nums[left] > nums[largest]:
            largest = left
        if right < n and nums[right] > nums[largest]:
            largest = right

        if largest != i:
            nums[i], nums[largest] = nums[largest], nums[i]
            self.heapify_helper(nums, largest, n)

        return nums

def main():
    s = Solution()
    nums = [5, 3, 1, 2, 7]
    result = s.heapify(nums)
    print(result)

