#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    vector<int> heapify(vector<int>& nums) {
        int n = nums.size();
        for (int i = n / 2 - 1; i >= 0; i--) {
            heapify_helper(nums, i, n);
        }
        return nums;

    def heapify_helper(nums, i, n):
        int largest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;

        if left < n && nums[left] > nums[largest]:
            largest = left;
        if right < n && nums[right] > nums[largest]:
            largest = right;

        if largest != i:
            swap(nums[i], nums[largest]);
            heapify_helper(nums, largest, n);

        return nums;

    void printVector(const vector<int>& vec) {
        cout << '[';
        for (int i = 0; i < vec.size(); i++) {
            cout << vec[i];
            if (i != vec.size() - 1) {
                cout << ', ';
            }
        }
        cout << ']' << endl;
    }

