    let n = nums.length;
    for (let i = Math.floor(n / 2) - 1; i >= 0; i--) {
        heapify_helper(nums, i, n);
    }
    return nums;

    function heapify_helper(nums, i, n) {
        let largest = i;
        let left = 2 * i + 1;
        let right = 2 * i + 2;

        if (left < n && nums[left] > nums[largest]) {
            largest = left;
        }
        if (right < n && nums[right] > nums[largest]) {
            largest = right;
        }

        if (largest != i) {
            [nums[i], nums[largest]] = [nums[largest], nums[i]];
            heapify_helper(nums, largest, n);
        }
        return nums;
    }
}

